1	/* =========================================================================
2	   app.js — コメントオーバーレイ エンジン本体
3	   =========================================================================
4	   このファイルは編集不要です（設定変更は config.js で行ってください）。
5	
6	   提供機能:
7	   - config.js の設定を読み込み、テーマ／位置／表示数などを適用
8	   - "demo" モード: ダミーの日本語コメントを自動生成
9	   - "websocket" モード: 指定 URL に接続し、JSON コメントを受信
10	       受信メッセージ形式: {"name":"...", "text":"...", "icon":"..."}
11	   - window.addComment({name, text, icon}) をグローバルに公開
12	     → 他の外部スクリプトや拡張からも直接コメントを追加できる
13	   ========================================================================= */
14	
15	(function () {
16	  "use strict";
17	
18	  // -----------------------------------------------------------------------
19	  // 設定の読み込み（config.js が読み込まれていない場合のフォールバックも用意）
20	  // -----------------------------------------------------------------------
21	  var DEFAULTS = {
22	    theme: "theme-dark",
23	    maxComments: 6,
24	    commentLifetimeMs: 8000,
25	    animationSpeedMs: 450,
26	    fontFamily: "'Yu Gothic UI', 'Hiragino Sans', 'Meiryo', sans-serif",
27	    verticalPosition: "bottom",
28	    horizontalPosition: "left",
29	    mode: "demo",
30	    websocketUrl: "ws://localhost:8080",
31	    reconnectIntervalMs: 3000,
32	    demoIntervalMinMs: 1800,
33	    demoIntervalMaxMs: 4000
34	  };
35	
36	  var userConfig = (window.OVERLAY_CONFIG && typeof window.OVERLAY_CONFIG === "object")
37	    ? window.OVERLAY_CONFIG
38	    : {};
39	
40	  var CONFIG = {};
41	  for (var key in DEFAULTS) {
42	    CONFIG[key] = (userConfig[key] !== undefined) ? userConfig[key] : DEFAULTS[key];
43	  }
44	
45	  // -----------------------------------------------------------------------
46	  // 初期セットアップ: body へのテーマ・フォント適用、コンテナの配置
47	  // -----------------------------------------------------------------------
48	  var VALID_THEMES = ["theme-dark", "theme-light", "theme-neon"];
49	  var theme = VALID_THEMES.indexOf(CONFIG.theme) !== -1 ? CONFIG.theme : DEFAULTS.theme;
50	
51	  document.body.classList.remove("theme-dark", "theme-light", "theme-neon");
52	  document.body.classList.add(theme);
53	  document.body.style.fontFamily = CONFIG.fontFamily;
54	
55	  var stack = document.getElementById("comment-stack");
56	  if (!stack) {
57	    stack = document.createElement("div");
58	    stack.id = "comment-stack";
59	    document.body.appendChild(stack);
60	  }
61	
62	  var vPos = (CONFIG.verticalPosition === "top") ? "top" : "bottom";
63	  var hPos = (CONFIG.horizontalPosition === "right") ? "right" : "left";
64	  stack.classList.add("pos-" + vPos, "pos-" + hPos);
65	
66	  // アニメーション速度は各カード生成時に animationDuration として直接設定する
67	  var slideClass = (hPos === "right") ? "slide-from-right" : "slide-from-left";
68	
69	  // -----------------------------------------------------------------------
70	  // ユーティリティ
71	  // -----------------------------------------------------------------------
72	  function pickInitial(name) {
73	    if (!name) return "?";
74	    var trimmed = String(name).trim();
75	    if (!trimmed) return "?";
76	    // サロゲートペア（絵文字等）を考慮して最初の1文字を取得
77	    var firstChar = Array.from(trimmed)[0];
78	    return firstChar.toUpperCase();
79	  }
80	
81	  function avatarColorFromString(str) {
82	    var hash = 0;
83	    for (var i = 0; i < str.length; i++) {
84	      hash = (hash << 5) - hash + str.charCodeAt(i);
85	      hash |= 0;
86	    }
87	    var hue1 = Math.abs(hash) % 360;
88	    var hue2 = (hue1 + 55) % 360;
89	    return "linear-gradient(135deg, hsl(" + hue1 + ",75%,60%), hsl(" + hue2 + ",75%,55%))";
90	  }
91	
92	  // -----------------------------------------------------------------------
93	  // コメントカードの生成・自動削除
94	  // -----------------------------------------------------------------------
95	  var activeCards = [];
96	
97	  function removeCard(card) {
98	    if (!card || card._removing) return;
99	    card._removing = true;
100	    card.classList.remove("anim-in", slideClass);
101	    card.classList.add("anim-out");
102	    card.style.animationDuration = CONFIG.animationSpeedMs + "ms";
103	
104	    var cleanup = function () {
105	      if (card.parentNode) card.parentNode.removeChild(card);
106	      var idx = activeCards.indexOf(card);
107	      if (idx !== -1) activeCards.splice(idx, 1);
108	    };
109	    card.addEventListener("animationend", cleanup, { once: true });
110	    // フォールバック（animationend が発火しない異常系への保険）
111	    setTimeout(cleanup, CONFIG.animationSpeedMs + 400);
112	  }
113	
114	  function enforceMaxComments() {
115	    var max = Math.max(1, parseInt(CONFIG.maxComments, 10) || DEFAULTS.maxComments);
116	    while (activeCards.length > max) {
117	      removeCard(activeCards[0]);
118	    }
119	  }
120	
121	  /**
122	   * 画面にコメントカードを1件追加する。
123	   * @param {Object} data - { name, text, icon }
124	   */
125	  function renderComment(data) {
126	    var name = (data && data.name) ? String(data.name) : "名無し";
127	    var text = (data && data.text !== undefined && data.text !== null) ? String(data.text) : "";
128	    var icon = (data && data.icon) ? String(data.icon) : "";
129	
130	    if (!text.trim() && !name.trim()) return; // 完全に空のメッセージは無視
131	
132	    var card = document.createElement("div");
133	    card.className = "comment-card " + slideClass;
134	    card.style.animationDuration = CONFIG.animationSpeedMs + "ms";
135	
136	    // アバター
137	    var avatar = document.createElement("div");
138	    avatar.className = "comment-avatar";
139	
140	    if (icon) {
141	      var img = document.createElement("img");
142	      img.src = icon;
143	      img.alt = "";
144	      img.referrerPolicy = "no-referrer";
145	      img.onerror = function () {
146	        // 画像読み込み失敗時は文字アバターにフォールバック
147	        avatar.innerHTML = "";
148	        avatar.style.background = avatarColorFromString(name);
149	        avatar.textContent = pickInitial(name);
150	      };
151	      avatar.appendChild(img);
152	    } else {
153	      avatar.style.background = avatarColorFromString(name);
154	      avatar.textContent = pickInitial(name);
155	    }
156	
157	    // 本文
158	    var body = document.createElement("div");
159	    body.className = "comment-body";
160	
161	    var nameEl = document.createElement("div");
162	    nameEl.className = "comment-name";
163	    nameEl.textContent = name;
164	
165	    var textEl = document.createElement("div");
166	    textEl.className = "comment-text";
167	    textEl.textContent = text; // textContent によりHTML注入を防止しつつ絵文字はそのまま表示
168	
169	    body.appendChild(nameEl);
170	    body.appendChild(textEl);
171	
172	    card.appendChild(avatar);
173	    card.appendChild(body);
174	
175	    // アニメーション開始のためフレームを1つ待つ
176	    requestAnimationFrame(function () {
177	      card.classList.add("anim-in");
178	    });
179	
180	    stack.appendChild(card);
181	    activeCards.push(card);
182	
183	    enforceMaxComments();
184	
185	    var lifetime = Math.max(1000, parseInt(CONFIG.commentLifetimeMs, 10) || DEFAULTS.commentLifetimeMs);
186	    card._timeoutId = setTimeout(function () {
187	      removeCard(card);
188	    }, lifetime);
189	  }
190	
191	  // -----------------------------------------------------------------------
192	  // グローバル公開 API: window.addComment({name, text, icon})
193	  // -----------------------------------------------------------------------
194	  window.addComment = function (data) {
195	    try {
196	      renderComment(data || {});
197	    } catch (err) {
198	      console.error("[overlay] addComment 失敗:", err);
199	    }
200	  };
201	
202	  // -----------------------------------------------------------------------
203	  // デモモード: ランダムな日本語コメントを自動生成
204	  // -----------------------------------------------------------------------
205	  var DEMO_NAMES = [
206	    "ねこ太郎", "ゲーム好き٩(ˊᗜˋ*)و", "通りすがりの視聴者", "もちもちうさぎ",
207	    "夜更かしリスナー", "コーヒー中毒者", "初見です", "常連さん",
208	    "プログラマー見習い", "VTuberファン", "深夜の住人", "推し活民"
209	  ];
210	
211	  var DEMO_MESSAGES = [
212	    "こんばんは〜！今日も配信楽しみにしてました✨",
213	    "うおおおおすごい！！🎉",
214	    "それ前にも見たことあるｗｗｗ",
215	    "初見です、よろしくお願いします😊",
216	    "今日のBGMいいですね🎵",
217	    "草",
218	    "がんばえー！応援してます💪",
219	    "それは無理じゃないですか？😂",
220	    "神プレイすぎる…",
221	    "コメント読んでくれてありがとうございます🙏",
222	    "次の配信も楽しみにしてます！",
223	    "もう少しでクリアできそう！",
224	    "画質きれい〜",
225	    "声がいい感じに通ってます🎤",
226	    "おつかれさまです、また来ます👋",
227	    "そこ右ですよ！右！！",
228	    "BGMの音量ちょうどいいですね",
229	    "やったー！おめでとうございます🎊",
230	    "今日は何時まで配信しますか？",
231	    "全然気づかなかった…さすが"
232	  ];
233	
234	  var demoTimerId = null;
235	
236	  function scheduleDemoComment() {
237	    var min = Math.max(200, parseInt(CONFIG.demoIntervalMinMs, 10) || DEFAULTS.demoIntervalMinMs);
238	    var max = Math.max(min, parseInt(CONFIG.demoIntervalMaxMs, 10) || DEFAULTS.demoIntervalMaxMs);
239	    var delay = min + Math.random() * (max - min);
240	
241	    demoTimerId = setTimeout(function () {
242	      var name = DEMO_NAMES[Math.floor(Math.random() * DEMO_NAMES.length)];
243	      var text = DEMO_MESSAGES[Math.floor(Math.random() * DEMO_MESSAGES.length)];
244	      window.addComment({ name: name, text: text, icon: "" });
245	      scheduleDemoComment();
246	    }, delay);
247	  }
248	
249	  function startDemoMode() {
250	    // 起動直後に最初のコメントをすぐ表示してから、ランダム間隔で続ける
251	    window.addComment({
252	      name: "デモモード",
253	      text: "これはデモ表示です。config.js の mode を \"websocket\" に変更すると実際のコメントを受信できます。",
254	      icon: ""
255	    });
256	    scheduleDemoComment();
257	  }
258	
259	  function stopDemoMode() {
260	    if (demoTimerId) {
261	      clearTimeout(demoTimerId);
262	      demoTimerId = null;
263	    }
264	  }
265	
266	  // -----------------------------------------------------------------------
267	  // WebSocket モード: 指定URLに接続しJSONコメントを受信、切断時は自動再接続
268	  // -----------------------------------------------------------------------
269	  var ws = null;
270	  var wsReconnectTimerId = null;
271	  var wsClosedByUser = false;
272	
273	  function connectWebSocket() {
274	    if (!CONFIG.websocketUrl) {
275	      console.warn("[overlay] websocketUrl が設定されていません。");
276	      return;
277	    }
278	
279	    try {
280	      ws = new WebSocket(CONFIG.websocketUrl);
281	    } catch (err) {
282	      console.error("[overlay] WebSocket 接続エラー:", err);
283	      scheduleReconnect();
284	      return;
285	    }
286	
287	    ws.onopen = function () {
288	      console.log("[overlay] WebSocket 接続成功: " + CONFIG.websocketUrl);
289	    };
290	
291	    ws.onmessage = function (event) {
292	      var payload;
293	      try {
294	        payload = JSON.parse(event.data);
295	      } catch (err) {
296	        console.warn("[overlay] JSON解析に失敗したメッセージを無視:", event.data);
297	        return;
298	      }
299	
300	      // 単体オブジェクト、または配列での一括送信の両方に対応
301	      if (Array.isArray(payload)) {
302	        payload.forEach(function (item) {
303	          window.addComment(item);
304	        });
305	      } else {
306	        window.addComment(payload);
307	      }
308	    };
309	
310	    ws.onerror = function (err) {
311	      console.warn("[overlay] WebSocket エラー:", err);
312	    };
313	
314	    ws.onclose = function () {
315	      ws = null;
316	      if (!wsClosedByUser) {
317	        console.warn("[overlay] WebSocket が切断されました。再接続を試みます…");
318	        scheduleReconnect();
319	      }
320	    };
321	  }
322	
323	  function scheduleReconnect() {
324	    if (wsReconnectTimerId) return;
325	    var interval = Math.max(500, parseInt(CONFIG.reconnectIntervalMs, 10) || DEFAULTS.reconnectIntervalMs);
326	    wsReconnectTimerId = setTimeout(function () {
327	      wsReconnectTimerId = null;
328	      connectWebSocket();
329	    }, interval);
330	  }
331	
332	  function startWebSocketMode() {
333	    wsClosedByUser = false;
334	    connectWebSocket();
335	  }
336	
337	  // -----------------------------------------------------------------------
338	  // 起動: config.mode に応じてモードを開始
339	  // -----------------------------------------------------------------------
340	  function init() {
341	    if (CONFIG.mode === "websocket") {
342	      startWebSocketMode();
343	    } else {
344	      startDemoMode();
345	    }
346	  }
347	
348	  if (document.readyState === "complete" || document.readyState === "interactive") {
349	    init();
350	  } else {
351	    document.addEventListener("DOMContentLoaded", init);
352	  }
353	
354	  // デバッグ・拡張用に内部状態を露出（任意）
355	  window.__overlay = {
356	    config: CONFIG,
357	    stopDemoMode: stopDemoMode,
358	    startDemoMode: startDemoMode
359	  };
360	
361	})();
