{
  "name": "comment-bridge",
  "version": "1.0.0",
  "description": "YouTube Live のコメントを OBS コメントオーバーレイへ橋渡しするブリッジツール（棒読みちゃん連携対応）",
  "main": "bridge.js",
  "type": "commonjs",
  "scripts": {
    "start": "node bridge.js"
  },
  "dependencies": {
    "ws": "^8.18.0"
  },
  "license": "UNLICENSED",
  "private": true
}

/* =========================================================================
   bridge.js — YouTube Live コメント → OBS コメントオーバーレイ 中継ブリッジ
   =========================================================================
   役割:
   - config.json を読み込む
   - ローカルに WebSocket サーバーを立てる（既定: ws://localhost:8080）
     → obs-comment-overlay 側を mode:"websocket" にして繋ぐと、
       受信したコメントがそのまま画面に表示されます。
   - YouTube Data API v3 の liveChatMessages を一定間隔でポーリングし、
     新着コメントだけをオーバーレイへ送信（重複排除あり）
   - 必要なら 棒読みちゃん の HTTP連携API にも投げて読み上げさせる
   - source:"test" のときは API キー不要でダミーコメントを自動生成

   送信するコメントの JSON 形式（オーバーレイ側 app.js と完全一致させること）:
     {"name": "表示名", "text": "コメント本文", "icon": "アイコンURL（任意・空文字可）"}
   ========================================================================= */

"use strict";

const fs = require("fs");
const path = require("path");
const http = require("http");
const https = require("https");
const { WebSocketServer } = require("ws");

// -------------------------------------------------------------------------
// 設定読み込み
// -------------------------------------------------------------------------
const CONFIG_PATH = path.join(__dirname, "config.json");

function loadConfig() {
  let raw;
  try {
    raw = fs.readFileSync(CONFIG_PATH, "utf8");
  } catch (err) {
    console.error("[起動エラー] config.json を読み込めませんでした: " + err.message);
    console.error("            comment-bridge フォルダの中に config.json があるか確認してください。");
    process.exit(1);
  }

  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (err) {
    console.error("[起動エラー] config.json の書式（JSON）が不正です: " + err.message);
    console.error("            カンマの付け忘れや引用符の閉じ忘れがないか確認してください。");
    process.exit(1);
  }
  return parsed;
}

const rawConfig = loadConfig();

const CONFIG = {
  source: rawConfig.source || "test",
  youtube: Object.assign(
    { apiKey: "", videoId: "", pollingFallbackMs: 5000 },
    rawConfig.youtube || {}
  ),
  websocket: Object.assign({ port: 8080 }, rawConfig.websocket || {}),
  bouyomi: Object.assign(
    { enabled: false, url: "http://localhost:50080/talk", voice: 0, volume: -1, speed: -1 },
    rawConfig.bouyomi || {}
  )
};

// -------------------------------------------------------------------------
// WebSocket サーバー（オーバーレイ側がここに接続してくる）
// -------------------------------------------------------------------------
const wsPort = parseInt(CONFIG.websocket.port, 10) || 8080;

let wss;
try {
  wss = new WebSocketServer({ port: wsPort });
} catch (err) {
  console.error("[起動エラー] WebSocket サーバーをポート " + wsPort + " で起動できませんでした。");
  console.error("            すでに他のプログラムがこのポートを使用している可能性があります。");
  console.error("            config.json の websocket.port を別の番号（例: 8081）に変更してみてください。");
  console.error("            詳細: " + err.message);
  process.exit(1);
}

let connectedClients = 0;

wss.on("connection", (socket) => {
  connectedClients++;
  console.log("[WebSocket] オーバーレイが接続しました（現在 " + connectedClients + " 件接続中）");

  socket.on("close", () => {
    connectedClients--;
    console.log("[WebSocket] オーバーレイの接続が切れました（現在 " + connectedClients + " 件接続中）");
  });

  socket.on("error", (err) => {
    console.warn("[WebSocket] クライアントとの通信でエラー: " + err.message);
  });
});

wss.on("error", (err) => {
  console.error("[WebSocket] サーバーエラー: " + err.message);
});

console.log("=========================================================");
console.log(" comment-bridge 起動");
console.log(" WebSocket サーバー: ws://localhost:" + wsPort);
console.log(" オーバーレイ側の config.js で mode を \"websocket\" にし、");
console.log(" websocketUrl を ws://localhost:" + wsPort + " に合わせてください。");
console.log(" 動作モード: " + CONFIG.source);
console.log("=========================================================");

/**
 * オーバーレイの contract {"name","text","icon"} に整形して全クライアントへ送信する。
 */
function broadcastComment({ name, text, icon }) {
  const payload = JSON.stringify({
    name: name || "名無し",
    text: text || "",
    icon: icon || ""
  });

  let sent = 0;
  wss.clients.forEach((client) => {
    // ws.OPEN === 1
    if (client.readyState === 1) {
      try {
        client.send(payload);
        sent++;
      } catch (err) {
        console.warn("[WebSocket] 送信に失敗したクライアントがあります: " + err.message);
      }
    }
  });

  const label = name || "名無し";
  console.log('[コメント] ' + label + ': ' + text + (sent > 0 ? "" : "  (※オーバーレイ未接続のため画面には表示されていません)"));
}

// -------------------------------------------------------------------------
// 棒読みちゃん 連携（HTTP連携API へ読み上げ依頼を送る）
// -------------------------------------------------------------------------
function sendToBouyomi(text) {
  if (!CONFIG.bouyomi || !CONFIG.bouyomi.enabled) return;
  if (!text || !String(text).trim()) return;

  try {
    const base = CONFIG.bouyomi.url || "http://localhost:50080/talk";
    const url = new URL(base);

    url.searchParams.set("text", text);
    if (CONFIG.bouyomi.voice !== undefined && CONFIG.bouyomi.voice !== null && CONFIG.bouyomi.voice !== -1) {
      url.searchParams.set("voice", String(CONFIG.bouyomi.voice));
    }
    if (CONFIG.bouyomi.volume !== undefined && CONFIG.bouyomi.volume !== null && CONFIG.bouyomi.volume !== -1) {
      url.searchParams.set("volume", String(CONFIG.bouyomi.volume));
    }
    if (CONFIG.bouyomi.speed !== undefined && CONFIG.bouyomi.speed !== null && CONFIG.bouyomi.speed !== -1) {
      url.searchParams.set("speed", String(CONFIG.bouyomi.speed));
    }

    const requester = url.protocol === "https:" ? https : http;
    const req = requester.get(url, (res) => {
      // レスポンス本体は不要だが、ストリームを消費してリクエストを完了させる
      res.resume();
    });
    req.on("error", (err) => {
      // 棒読みちゃんが起動していない等。ブリッジ自体は絶対に落とさない。
      console.warn("[棒読みちゃん] 連携に失敗しました（起動していない可能性があります）: " + err.message);
    });
    req.setTimeout(3000, () => {
      req.destroy();
    });
  } catch (err) {
    console.warn("[棒読みちゃん] 連携処理中に例外が発生しました: " + err.message);
  }
}

// -------------------------------------------------------------------------
// 共通: コメント1件を処理する（オーバーレイ送信 + 棒読みちゃん連携）
// -------------------------------------------------------------------------
function handleIncomingComment({ name, text, icon }) {
  broadcastComment({ name, text, icon });
  sendToBouyomi(text);
}

// =========================================================================
// テストモード（source: "test"）— API キー不要でダミーコメントを生成
// =========================================================================
const TEST_NAMES = [
  "ねこ太郎", "通りすがりの視聴者", "もちもちうさぎ", "夜更かしリスナー",
  "初見です", "常連さん", "VTuberファン", "深夜の住人"
];
const TEST_MESSAGES = [
  "こんばんは〜！今日も配信楽しみにしてました✨",
  "うおおおおすごい！！🎉",
  "それ前にも見たことあるｗｗｗ",
  "初見です、よろしくお願いします😊",
  "今日のBGMいいですね🎵",
  "草",
  "がんばえー！応援してます💪",
  "テストコメントです（comment-bridge 動作確認用）"
];

function startTestMode() {
  console.log("[テストモード] ダミーコメントを自動生成します。YouTube API キーは不要です。");
