/**
 * Node 18+ の組み込み fetch を利用して YouTube Data API v3 を呼び出す。
 * 失敗時は分かりやすいエラーメッセージを投げる。
 */
async function youtubeApiGet(endpoint, params) {
  const url = new URL("https://www.googleapis.com/youtube/v3/" + endpoint);
  for (const key in params) {
    if (params[key] !== undefined && params[key] !== null) {
      url.searchParams.set(key, params[key]);
    }
  }
  url.searchParams.set("key", CONFIG.youtube.apiKey);

  let res;
  try {
    res = await fetch(url);
  } catch (err) {
    throw new Error("YouTube API への接続に失敗しました（ネットワーク環境を確認してください）: " + err.message);
  }

  let body;
  try {
    body = await res.json();
  } catch (err) {
    throw new Error("YouTube API のレスポンス解析に失敗しました: " + err.message);
  }

  if (!res.ok) {
    const apiMessage = (body && body.error && body.error.message) ? body.error.message : ("HTTPステータス " + res.status);
    const reason = (body && body.error && Array.isArray(body.error.errors) && body.error.errors[0])
      ? body.error.errors[0].reason
      : null;

    if (res.status === 403 && reason === "quotaExceeded") {
      throw new YoutubeApiError("QUOTA_EXCEEDED", "YouTube API の本日分の利用上限（クォータ）に達しました。" +
        " 無料枠は1日あたり既定 10,000 ユニットです。翌日（太平洋時間 0時）にリセットされます。");
    }
    if (res.status === 400 || res.status === 403) {
      throw new YoutubeApiError("INVALID_KEY", "YouTube API キーが正しくないか、YouTube Data API v3 が有効化されていません。" +
        " Google Cloud Console で API キーと有効化状況を確認してください。詳細: " + apiMessage);
    }
    throw new YoutubeApiError("API_ERROR", "YouTube API エラー: " + apiMessage);
  }

  return body;
}

class YoutubeApiError extends Error {
  constructor(code, message) {
    super(message);
    this.code = code;
  }
}

/**
 * videoId から liveChatId を取得する。
 */
async function resolveLiveChatId(videoId) {
  const body = await youtubeApiGet("videos", {
    part: "liveStreamingDetails,snippet",
    id: videoId
  });

  if (!body.items || body.items.length === 0) {
    throw new YoutubeApiError("VIDEO_NOT_FOUND",
      "指定された videoId の動画が見つかりませんでした。videoId が正しいか確認してください: " + videoId);
  }

  const item = body.items[0];
  const liveChatId = item.liveStreamingDetails && item.liveStreamingDetails.activeLiveChatId;

  if (!liveChatId) {
    throw new YoutubeApiError("NO_LIVE_CHAT",
      "この動画には現在有効なライブチャットがありません。配信が開始されているか、" +
      "チャットが有効になっているか確認してください（配信終了後はチャットが取得できなくなります）。");
  }

  return liveChatId;
}

const seenMessageIds = new Set();
const MAX_SEEN_IDS = 5000;

function rememberMessageId(id) {
  seenMessageIds.add(id);
  // 無制限に増え続けないよう、古いものを間引く（長時間配信対策）
  if (seenMessageIds.size > MAX_SEEN_IDS) {
    const it = seenMessageIds.values();
    for (let i = 0; i < 1000; i++) {
      const v = it.next();
      if (v.done) break;
      seenMessageIds.delete(v.value);
    }
  }
}

let nextPageToken = undefined;
let pollTimer = null;
let consecutiveErrorCount = 0;

async function pollLiveChat(liveChatId) {
  let body;
  try {
    body = await youtubeApiGet("liveChat/messages", {
      liveChatId: liveChatId,
      part: "snippet,authorDetails",
      pageToken: nextPageToken
    });
  } catch (err) {
    consecutiveErrorCount++;
    if (err instanceof YoutubeApiError && err.code === "QUOTA_EXCEEDED") {
      console.error("[YouTube] " + err.message);
      console.error("[YouTube] クォータが回復するまで comment-bridge を停止するか、明日まで待ってください。");
      // クォータ切れは復帰しないことが多いのでポーリングを止める
      return;
    }

    console.error("[YouTube] チャット取得に失敗しました: " + err.message);

    if (consecutiveErrorCount >= 5) {
      console.error("[YouTube] エラーが連続しています。liveChatId の再取得を試みます…");
      try {
        const newLiveChatId = await resolveLiveChatId(CONFIG.youtube.videoId);
        consecutiveErrorCount = 0;
        nextPageToken = undefined;
        pollTimer = setTimeout(() => pollLiveChat(newLiveChatId), CONFIG.youtube.pollingFallbackMs);
        return;
      } catch (err2) {
        console.error("[YouTube] liveChatId の再取得にも失敗しました: " + err2.message);
      }
    }

    pollTimer = setTimeout(() => pollLiveChat(liveChatId), CONFIG.youtube.pollingFallbackMs);
    return;
  }

  consecutiveErrorCount = 0;
  nextPageToken = body.nextPageToken;

  const items = body.items || [];
  for (const item of items) {
    const id = item.id;
    if (!id || seenMessageIds.has(id)) continue;
    rememberMessageId(id);

    const snippet = item.snippet || {};
    const author = item.authorDetails || {};

    // textMessageEvent 以外（メンバー加入やスーパーチャット等）も displayMessage があれば拾う
    const text = snippet.displayMessage !== undefined ? snippet.displayMessage : "";
    if (!text && !author.displayName) continue;

    handleIncomingComment({
      name: author.displayName || "名無し",
      text: text,
      icon: author.profileImageUrl || ""
    });
  }

  const interval = (typeof body.pollingIntervalMillis === "number" && body.pollingIntervalMillis > 0)
    ? body.pollingIntervalMillis
    : CONFIG.youtube.pollingFallbackMs;

  pollTimer = setTimeout(() => pollLiveChat(liveChatId), interval);
}

async function startYoutubeMode() {
  if (!CONFIG.youtube.apiKey) {
    console.error("[起動エラー] config.json の youtube.apiKey が設定されていません。");
    console.error("            Google Cloud Console で取得した YouTube Data API v3 用の API キーを設定してください。");
    console.error("            詳しい手順は README_bridge.md を参照してください。");
    return;
  }
  if (!CONFIG.youtube.videoId) {
    console.error("[起動エラー] config.json の youtube.videoId が設定されていません。");
    console.error("            ライブ配信の動画ID（URLの v= の後ろの部分）を設定してください。");
    return;
  }

  console.log("[YouTube] videoId: " + CONFIG.youtube.videoId + " からライブチャットを検索しています…");

  let liveChatId;
  try {
    liveChatId = await resolveLiveChatId(CONFIG.youtube.videoId);
  } catch (err) {
    if (err instanceof YoutubeApiError) {
      console.error("[起動エラー] " + err.message);
    } else {
      console.error("[起動エラー] ライブチャットの特定に失敗しました: " + err.message);
    }
    console.error("[YouTube] 30秒後に再試行します（配信開始前の場合は配信を開始してください）…");
    setTimeout(startYoutubeMode, 30000);
    return;
  }

  console.log("[YouTube] ライブチャットに接続しました。コメントの取得を開始します。");
  pollLiveChat(liveChatId);
}

// =========================================================================
// 起動
// =========================================================================
if (CONFIG.source === "youtube") {
  if (typeof fetch !== "function") {
    console.error("[起動エラー] このNode.jsのバージョンには組み込み fetch がありません。");
    console.error("            Node.js 18 以降（LTS推奨）をインストールしてください: https://nodejs.org/");
    process.exit(1);
  }
  startYoutubeMode();
} else {
  startTestMode();
}

// -------------------------------------------------------------------------
// 終了処理
// -------------------------------------------------------------------------
process.on("SIGINT", () => {
  console.log("\n[comment-bridge] 終了します…");
  if (pollTimer) clearTimeout(pollTimer);
  wss.close(() => process.exit(0));
  setTimeout(() => process.exit(0), 1000);
});

process.on("uncaughtException", (err) => {
  console.error("[予期しないエラー] " + (err && err.stack ? err.stack : err));
  console.error("[comment-bridge] プログラムは継続を試みます。問題が続く場合は再起動してください。");
});

