288	    part: "liveStreamingDetails,snippet",
289	    id: videoId
290	  });
291	
292	  if (!body.items || body.items.length === 0) {
293	    throw new YoutubeApiError("VIDEO_NOT_FOUND",
294	      "指定された videoId の動画が見つかりませんでした。videoId が正しいか確認してください: " + videoId);
295	  }
296	
297	  const item = body.items[0];
298	  const liveChatId = item.liveStreamingDetails && item.liveStreamingDetails.activeLiveChatId;
299	
300	  if (!liveChatId) {
301	    throw new YoutubeApiError("NO_LIVE_CHAT",
302	      "この動画には現在有効なライブチャットがありません。配信が開始されているか、" +
303	      "チャットが有効になっているか確認してください（配信終了後はチャットが取得できなくなります）。");
304	  }
305	
306	  return liveChatId;
307	}
308	
309	const seenMessageIds = new Set();
310	const MAX_SEEN_IDS = 5000;
311	
312	function rememberMessageId(id) {
313	  seenMessageIds.add(id);
314	  // 無制限に増え続けないよう、古いものを間引く（長時間配信対策）
315	  if (seenMessageIds.size > MAX_SEEN_IDS) {
316	    const it = seenMessageIds.values();
317	    for (let i = 0; i < 1000; i++) {
318	      const v = it.next();
319	      if (v.done) break;
320	      seenMessageIds.delete(v.value);
321	    }
322	  }
323	}
324	
325	let nextPageToken = undefined;
326	let pollTimer = null;
327	let consecutiveErrorCount = 0;
328	
329	async function pollLiveChat(liveChatId) {
330	  let body;
331	  try {
332	    body = await youtubeApiGet("liveChat/messages", {
333	      liveChatId: liveChatId,
334	      part: "snippet,authorDetails",
335	      pageToken: nextPageToken
336	    });
337	  } catch (err) {
338	    consecutiveErrorCount++;
339	    if (err instanceof YoutubeApiError && err.code === "QUOTA_EXCEEDED") {
340	      console.error("[YouTube] " + err.message);
341	      console.error("[YouTube] クォータが回復するまで comment-bridge を停止するか、明日まで待ってください。");
342	      // クォータ切れは復帰しないことが多いのでポーリングを止める
343	      return;
344	    }
345	
346	    console.error("[YouTube] チャット取得に失敗しました: " + err.message);
347	
348	    if (consecutiveErrorCount >= 5) {
349	      console.error("[YouTube] エラーが連続しています。liveChatId の再取得を試みます…");
350	      try {
351	        const newLiveChatId = await resolveLiveChatId(CONFIG.youtube.videoId);
352	        consecutiveErrorCount = 0;
353	        nextPageToken = undefined;
354	        pollTimer = setTimeout(() => pollLiveChat(newLiveChatId), CONFIG.youtube.pollingFallbackMs);
355	        return;
356	      } catch (err2) {
357	        console.error("[YouTube] liveChatId の再取得にも失敗しました: " + err2.message);
358	      }
359	    }
360	
361	    pollTimer = setTimeout(() => pollLiveChat(liveChatId), CONFIG.youtube.pollingFallbackMs);
362	    return;
363	  }
364	
365	  consecutiveErrorCount = 0;
366	  nextPageToken = body.nextPageToken;
367	
368	  const items = body.items || [];
369	  for (const item of items) {
370	    const id = item.id;
371	    if (!id || seenMessageIds.has(id)) continue;
372	    rememberMessageId(id);
373	
374	    const snippet = item.snippet || {};
375	    const author = item.authorDetails || {};
376	
377	    // textMessageEvent 以外（メンバー加入やスーパーチャット等）も displayMessage があれば拾う
378	    const text = snippet.displayMessage !== undefined ? snippet.displayMessage : "";
379	    if (!text && !author.displayName) continue;
380	
381	    handleIncomingComment({
382	      name: author.displayName || "名無し",
383	      text: text,
384	      icon: author.profileImageUrl || ""
385	    });
386	  }
387	
388	  const interval = (typeof body.pollingIntervalMillis === "number" && body.pollingIntervalMillis > 0)
389	    ? body.pollingIntervalMillis
390	    : CONFIG.youtube.pollingFallbackMs;
391	
392	  pollTimer = setTimeout(() => pollLiveChat(liveChatId), interval);
393	}
394	
395	async function startYoutubeMode() {
396	  if (!CONFIG.youtube.apiKey) {
397	    console.error("[起動エラー] config.json の youtube.apiKey が設定されていません。");
