420	    setTimeout(startYoutubeMode, 30000);
421	    return;
422	  }
423	
424	  console.log("[YouTube] ライブチャットに接続しました。コメントの取得を開始します。");
425	  pollLiveChat(liveChatId);
426	}
427	
428	// =========================================================================
